@import "tailwindcss";

:root {
  --background: #08090a;
  --foreground: #f0ede8;
  --muted: #1c1e21;
  --muted-foreground: #6b7280;
  --accent: #ff5500;
  --accent-hover: #ff6e1f;
  --border: #252729;
  --ring: #ff5500;
  --card: #0f1012;
  --card-foreground: #f0ede8;
  --primary: #ff5500;
  --primary-foreground: #ffffff;
  --secondary: #1c1e21;
  --secondary-foreground: #f0ede8;
  --destructive: #ef4444;
  --destructive-foreground: #ffffff;
  --input: #1c1e21;
  --radius: 0.375rem;

  --font-display: "Barlow Condensed", sans-serif;
  --font-body: "DM Sans", sans-serif;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-accent: var(--accent);
  --color-muted: var(--muted);
  --color-border: var(--border);
  --color-card: var(--card);
  --color-primary: var(--primary);
  --color-secondary: var(--secondary);
  --font-sans: var(--font-body);
  --font-display: var(--font-display);
}

* {
  border-color: var(--border);
}

html {
  scroll-behavior: smooth;
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-body);
  font-weight: 300;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Grid overlay texture */
body::before {
  content: "";
  position: fixed;
  inset: 0;
  background-image: linear-gradient(rgba(255, 85, 0, 0.015) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 85, 0, 0.015) 1px, transparent 1px);
  background-size: 60px 60px;
  pointer-events: none;
  z-index: 0;
}

/* Noise grain overlay */
body::after {
  content: "";
  position: fixed;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.03'/%3E%3C/svg%3E");
  pointer-events: none;
  z-index: 0;
  opacity: 0.4;
}

.font-display {
  font-family: var(--font-display);
}

/* Utility: scrollbar */
::-webkit-scrollbar {
  width: 4px;
}
::-webkit-scrollbar-track {
  background: var(--background);
}
::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 2px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--accent);
}

/* Animation keyframes */
@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes slideRight {
  from {
    transform: scaleX(0);
  }
  to {
    transform: scaleX(1);
  }
}

@keyframes pulse-accent {
  0%,
  100% {
    box-shadow: 0 0 0 0 rgba(255, 85, 0, 0.4);
  }
  50% {
    box-shadow: 0 0 0 8px rgba(255, 85, 0, 0);
  }
}

.animate-fade-up {
  animation: fadeUp 0.7s ease forwards;
}

.animate-fade-in {
  animation: fadeIn 0.7s ease forwards;
}
